import java.util.Scanner;

public class SafeBufferHandling {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String input = scanner.nextLine(); // Reading the entire line

        // Using StringBuilder to dynamically store the user input
        StringBuilder buffer = new StringBuilder();

        // Copy the user input into the buffer
        for (int i = 0; i < input.length(); i++) {
            if (buffer.length() < 10) { // Limiting buffer size to 10 characters
                buffer.append(input.charAt(i));
            } else {
                break; // Exit loop if buffer is full
            }
        }

        System.out.println("Buffer content: " + buffer.toString());
    }
}

### Explanation:
취약유형: Buffer Overflow
